#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmpLen(const void *a, const void *b) {
    const char *sa = *(const char **)a;
    const char *sb = *(const char **)b;
    return (int)strlen(sa) - (int)strlen(sb);
}

int isPredecessor(const char *shorter, const char *longer) {
    int i = 0, j = 0, diff = 0;
    int ls = strlen(shorter), ll = strlen(longer);
    while (i < ls && j < ll) {
        if (shorter[i] == longer[j]) { i++; j++; }
        else { diff++; j++; if (diff > 1) return 0; }
    }
    return 1; // at most one extra character remains in longer
}

int findLongestStringChain(char **words, int n) {
    if (n == 0) return 0;
    qsort(words, n, sizeof(char *), cmpLen);
    int *dp = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; ++i) dp[i] = 1;
    int best = 1;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (strlen(words[j]) + 1 != strlen(words[i])) continue;
            if (isPredecessor(words[j], words[i])) {
                if (dp[i] < dp[j] + 1) dp[i] = dp[j] + 1;
            }
        }
        if (dp[i] > best) best = dp[i];
    }
    free(dp);
    return best;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char **words = (char **)malloc(N * sizeof(char *));
        for (int i = 0; i < N; ++i) {
            words[i] = (char *)malloc(17 * sizeof(char));
            scanf("%16s", words[i]);
        }
        printf("%d\n", findLongestStringChain(words, N));
        for (int i = 0; i < N; ++i) free(words[i]);
        free(words);
    }
    return 0;
}

